CREATE TABLE IF NOT EXISTS vacancies (
    title VARCHAR(255) NOT NULL,
    requirements TEXT NOT NULL,
    duties TEXT NOT NULL,
    conditions TEXT NOT NULL,
    is_active BOOLEAN DEFAULT true,
    is_actual BOOLEAN DEFAULT true,
    position INTEGER
);

